import httpx
import json
from dataclasses import dataclass, field
from datetime import date, timedelta
from typing import Optional

OPENAI_MODELS_URL = "https://api.openai.com/v1/models"

# Static EOL registry — updated quarterly from provider deprecation pages
MODEL_EOL: dict[str, date] = {
    "gpt-3.5-turbo-0301": date(2024, 6, 13),
    "gpt-3.5-turbo-0613": date(2024, 9, 13),
    "gpt-4-0314":         date(2024, 6, 13),
}

PINNED_MODELS: list[str] = [
    "gpt-4o-2024-11-20",
    "claude-sonnet-4-6",
    "gemini-1.5-pro-002",
]

@dataclass
class ModelStatus:
    model_id: str
    available: bool
    eol_date: Optional[date] = None
    days_to_eol: Optional[int] = None
    radar_ring: str = "Unknown"

    def compute_ring(self) -> None:
        if not self.available:
            self.radar_ring = "Hold"
            return
        if self.eol_date is None:
            self.radar_ring = "Adopt"
            return
        days = (self.eol_date - date.today()).days
        if days < 0:
            self.radar_ring = "Hold"
        elif days < 90:
            self.radar_ring = "Hold"   # imminent deprecation
        elif days < 365:
            self.radar_ring = "Trial"  # warn: plan migration
        else:
            self.radar_ring = "Adopt"


def check_models(api_key: str) -> list[ModelStatus]:
    headers = {"Authorization": f"Bearer {api_key}"}
    resp = httpx.get(OPENAI_MODELS_URL, headers=headers, timeout=10)
    available_ids = {m["id"] for m in resp.json().get("data", [])}

    statuses = []
    for model_id in PINNED_MODELS:
        eol = MODEL_EOL.get(model_id)
        days = (eol - date.today()).days if eol else None
        status = ModelStatus(
            model_id=model_id,
            available=model_id in available_ids,
            eol_date=eol,
            days_to_eol=days,
        )
        status.compute_ring()
        statuses.append(status)
    return statuses


# Weekly scheduler entry point (called by cron / GitHub Actions)
def run_radar_check(api_key: str) -> None:
    statuses = check_models(api_key)
    alerts = []
    for s in statuses:
        print(f"{s.model_id:40s}  ring={s.radar_ring:6s}  available={s.available}")
        if s.radar_ring == "Hold":
            alerts.append(f"ALERT: {s.model_id} is in Hold — migrate immediately")
        elif s.radar_ring == "Trial" and s.days_to_eol and s.days_to_eol < 180:
            alerts.append(f"WARN: {s.model_id} EOL in {s.days_to_eol} days — schedule migration")
    if alerts:
        for a in alerts:
            print(a)
        raise SystemExit(1)  # fail CI/monitoring job to trigger alert
